   664→    private static TcpListener StartTcpServer(int port, Func<TcpClient, Task> handler)
   665→    {
   666→        var server = new TcpListener(IPAddress.Loopback, port);
   667→        server.Start();
   668→        Task.Run(() => AcceptClientsAsync(server, handler));
   669→        return server;
   670→    }
   671→
   672→    private static async Task AcceptClientsAsync(TcpListener server, Func<TcpClient, Task> handler)
   673→    {
   674→        while (true)
   675→        {
   676→            var client = await server.AcceptTcpClientAsync();
   677→            _ = Task.Run(() => handler(client));
   678→        }
   679→    }
