   681→    private static async Task MockDelimiterPackageAsync(TcpClient client)
   682→    {
   683→        using var stream = client.GetStream();
   684→        while (true)
   685→        {
   686→            var buffer = new byte[10240];
   687→            var len = await stream.ReadAsync(buffer);
   688→            if (len == 0)
   689→            {
   690→                break;
   691→            }
   692→
   693→            // 回写数据到客户端
   694→            var block = new ReadOnlyMemory<byte>(buffer, 0, len);
   695→            await stream.WriteAsync(block, CancellationToken.None);
   696→
   697→            await Task.Delay(20);
   698→
   699→            // 模拟拆包发送第二段数据
   700→            await stream.WriteAsync(new byte[] { 13, 10, 0x5, 0x6, 13, 10 }, CancellationToken.None);
