public async ValueTask<bool> ConnectAsync(IPEndPoint endPoint, CancellationToken token = default)
{
    if (IsConnected)
    {
        return true;
    }

    // Fast-path: if another connect is already in-flight, await it without taking a lock.
    var inFlight = Volatile.Read(ref _connectTask);
    if (inFlight != null)
    {
        return await WaitConnectAsync(inFlight, token).ConfigureAwait(false);
    }

    await _connectLock.WaitAsync(token).ConfigureAwait(false);
    try
    {
        if (IsConnected)
        {
            return true;
        }

        inFlight = _connectTask;
        if (inFlight == null)
        {
            var provider = ServiceProvider?.GetRequiredService<ISocketClientProvider>()
                ?? throw new InvalidOperationException("SocketClientProvider is not registered in the service provider.");

            SocketClientProvider = provider;

            // Run actual connect work once; concurrent callers share this task.
            inFlight = _connectTask = ConnectInternalAsync(provider, endPoint, token);
        }
    }
    finally
    {
        _connectLock.Release();
    }

    return await WaitConnectAsync(inFlight, token).ConfigureAwait(false);
}

private async Task<bool> WaitConnectAsync(Task<bool> connectTask, CancellationToken token)
{
    if (!token.CanBeCanceled)
    {
        return await connectTask.ConfigureAwait(false);
    }

    // Ensure per-caller cancellation does not cancel the shared connect attempt.
    var cancelTask = Task.Delay(Timeout.InfiniteTimeSpan, token);
    var completed = await Task.WhenAny(connectTask, cancelTask).ConfigureAwait(false);
    if (completed == cancelTask)
    {
        return false;
    }
    return await connectTask.ConfigureAwait(false);
}

private async Task<bool> ConnectInternalAsync(ISocketClientProvider provider, IPEndPoint endPoint, CancellationToken token)
{
    var ret = false;
    try
    {
        ret = await ConnectCoreAsync(provider, endPoint, token).ConfigureAwait(false);
        if (ret == false)
        {
            Reconnect();
        }
    }
    catch (OperationCanceledException ex)
    {
        if (token.IsCancellationRequested)
        {
            Log(LogLevel.Warning, ex, $"TCP Socket connect operation was canceled from {LocalEndPoint} to {endPoint}");
        }
        else
        {
            Log(LogLevel.Warning, ex, $"TCP Socket connect operation timed out from {LocalEndPoint} to {endPoint}");
            Reconnect();
        }
    }
    catch (Exception ex)
    {
        Log(LogLevel.Error, ex, $"TCP Socket connection failed from {LocalEndPoint} to {endPoint}");
        Reconnect();
    }
    finally
    {
        // Allow subsequent ConnectAsync calls.
        Volatile.Write(ref _connectTask, null);
    }

    return ret;
}

