    [Fact]
    public async Task ConnectAsync_Concurrent_Cancel_DoesNotCancelSharedConnect()
    {
        // 同一个 client 并发 ConnectAsync：一个调用取消不应导致另一个调用被取消
        var provider = new MockConcurrentConnectSocketProvider(delay: 200);
        var client = CreateClient(builder =>
        {
            builder.AddTransient<ISocketClientProvider>(p => provider);
        });

        var ep = Utility.ConvertToIpEndPoint("localhost", 0);

        var cts = new CancellationTokenSource();
        cts.Cancel();
        var taskCanceled = client.ConnectAsync(ep, cts.Token).AsTask();
        var taskNormal = client.ConnectAsync(ep).AsTask();

        var results = await Task.WhenAll(taskCanceled, taskNormal);

        Assert.Contains(false, results);
        Assert.Contains(true, results);

        // 并发只应触发一次底层 ConnectAsync
        Assert.Equal(1, provider.ConnectCount);
    }

